#include "jayess_runtime.h"
#include <cubeb/cubeb.h>
#include <pthread.h>
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>
#include "miniaudio.h"
#include "stb_vorbis.c"

typedef struct jayess_audio_stream_state {
    cubeb_stream *stream;
    pthread_mutex_t mutex;
    float *queued_samples;
    size_t queued_sample_count;
    size_t queued_sample_capacity;
    size_t read_sample_offset;
    uint32_t sample_rate;
    uint32_t channels;
    uint32_t latency_frames;
    cubeb_sample_format format;
    unsigned long long submitted_frames;
    unsigned long long consumed_frames;
    unsigned long long captured_frames;
    unsigned long long callback_count;
    unsigned long long underrun_count;
    int running;
    int last_state;
    int capture_mode;
    int *pending_events;
    size_t pending_event_count;
    size_t pending_event_capacity;
} jayess_audio_stream_state;

static void jayess_audio_context_finalize(void *handle) {
    if (handle != NULL) {
        cubeb_destroy((cubeb *) handle);
    }
}

static const char *jayess_audio_device_type_text(cubeb_device_type type) {
    switch (type) {
        case CUBEB_DEVICE_TYPE_INPUT:
            return "input";
        case CUBEB_DEVICE_TYPE_OUTPUT:
            return "output";
        case CUBEB_DEVICE_TYPE_UNKNOWN:
        default:
            return "unknown";
    }
}

static const char *jayess_audio_device_state_text(cubeb_device_state state) {
    switch (state) {
        case CUBEB_DEVICE_STATE_DISABLED:
            return "disabled";
        case CUBEB_DEVICE_STATE_UNPLUGGED:
            return "unplugged";
        case CUBEB_DEVICE_STATE_ENABLED:
            return "enabled";
        default:
            return "unknown";
    }
}

static const char *jayess_audio_stream_state_text(int state) {
    switch (state) {
        case CUBEB_STATE_STARTED:
            return "started";
        case CUBEB_STATE_STOPPED:
            return "stopped";
        case CUBEB_STATE_DRAINED:
            return "drained";
        case CUBEB_STATE_ERROR:
            return "error";
        default:
            return "unknown";
    }
}

static const char *jayess_audio_event_text(int event_code) {
    switch (event_code) {
        case CUBEB_STATE_STARTED:
            return "started";
        case CUBEB_STATE_STOPPED:
            return "stopped";
        case CUBEB_STATE_DRAINED:
            return "drained";
        case CUBEB_STATE_ERROR:
            return "error";
        case 100:
            return "underrun";
        default:
            return "unknown";
    }
}

static jayess_value *jayess_audio_format_value(cubeb_device_fmt format) {
    jayess_array *formats = jayess_array_new();
    if (formats == NULL) {
        return jayess_value_undefined();
    }
    if ((format & CUBEB_DEVICE_FMT_S16LE) != 0) {
        jayess_array_push_value(formats, jayess_value_from_string("s16le"));
    }
    if ((format & CUBEB_DEVICE_FMT_S16BE) != 0) {
        jayess_array_push_value(formats, jayess_value_from_string("s16be"));
    }
    if ((format & CUBEB_DEVICE_FMT_F32LE) != 0) {
        jayess_array_push_value(formats, jayess_value_from_string("f32le"));
    }
    if ((format & CUBEB_DEVICE_FMT_F32BE) != 0) {
        jayess_array_push_value(formats, jayess_value_from_string("f32be"));
    }
    return jayess_value_from_array(formats);
}

static cubeb_sample_format jayess_audio_stream_format_from_string(const char *text) {
    if (text == NULL || strcmp(text, "f32") == 0 || strcmp(text, "float32") == 0 || strcmp(text, "f32ne") == 0) {
        return CUBEB_SAMPLE_FLOAT32NE;
    }
    if (strcmp(text, "s16") == 0 || strcmp(text, "s16ne") == 0) {
        return CUBEB_SAMPLE_S16NE;
    }
    return (cubeb_sample_format)-1;
}

static const char *jayess_audio_stream_format_text(cubeb_sample_format format) {
    switch (format) {
        case CUBEB_SAMPLE_FLOAT32NE:
            return "f32";
        case CUBEB_SAMPLE_S16NE:
            return "s16";
        default:
            return "unknown";
    }
}

static uint16_t jayess_audio_read_u16le(const unsigned char *bytes) {
    return (uint16_t)((uint16_t)bytes[0] | ((uint16_t)bytes[1] << 8));
}

static uint32_t jayess_audio_read_u32le(const unsigned char *bytes) {
    return (uint32_t)bytes[0] |
           ((uint32_t)bytes[1] << 8) |
           ((uint32_t)bytes[2] << 16) |
           ((uint32_t)bytes[3] << 24);
}

static jayess_value *jayess_audio_preferred_value(cubeb_device_pref preferred) {
    jayess_array *prefs = jayess_array_new();
    if (prefs == NULL) {
        return jayess_value_undefined();
    }
    if ((preferred & CUBEB_DEVICE_PREF_MULTIMEDIA) != 0) {
        jayess_array_push_value(prefs, jayess_value_from_string("multimedia"));
    }
    if ((preferred & CUBEB_DEVICE_PREF_VOICE) != 0) {
        jayess_array_push_value(prefs, jayess_value_from_string("voice"));
    }
    if ((preferred & CUBEB_DEVICE_PREF_NOTIFICATION) != 0) {
        jayess_array_push_value(prefs, jayess_value_from_string("notification"));
    }
    return jayess_value_from_array(prefs);
}

static jayess_value *jayess_audio_device_info_value(const cubeb_device_info *device) {
    jayess_object *object = jayess_object_new();
    if (object == NULL) {
        return jayess_value_undefined();
    }
    jayess_object_set_value(object, "deviceId", device->device_id != NULL ? jayess_value_from_string(device->device_id) : jayess_value_undefined());
    jayess_object_set_value(object, "friendlyName", device->friendly_name != NULL ? jayess_value_from_string(device->friendly_name) : jayess_value_undefined());
    jayess_object_set_value(object, "groupId", device->group_id != NULL ? jayess_value_from_string(device->group_id) : jayess_value_undefined());
    jayess_object_set_value(object, "vendorName", device->vendor_name != NULL ? jayess_value_from_string(device->vendor_name) : jayess_value_undefined());
    jayess_object_set_value(object, "type", jayess_value_from_string(jayess_audio_device_type_text(device->type)));
    jayess_object_set_value(object, "state", jayess_value_from_string(jayess_audio_device_state_text(device->state)));
    jayess_object_set_value(object, "preferred", jayess_audio_preferred_value(device->preferred));
    jayess_object_set_value(object, "format", jayess_audio_format_value(device->format));
    jayess_object_set_value(object, "defaultFormat", jayess_audio_format_value(device->default_format));
    jayess_object_set_value(object, "maxChannels", jayess_value_from_number((double) device->max_channels));
    jayess_object_set_value(object, "defaultRate", jayess_value_from_number((double) device->default_rate));
    jayess_object_set_value(object, "maxRate", jayess_value_from_number((double) device->max_rate));
    jayess_object_set_value(object, "minRate", jayess_value_from_number((double) device->min_rate));
    jayess_object_set_value(object, "latencyLo", jayess_value_from_number((double) device->latency_lo));
    jayess_object_set_value(object, "latencyHi", jayess_value_from_number((double) device->latency_hi));
    return jayess_value_from_object(object);
}

static jayess_value *jayess_audio_list_devices(cubeb *context, cubeb_device_type type) {
    cubeb_device_collection collection;
    jayess_array *devices = NULL;
    size_t i = 0;
    memset(&collection, 0, sizeof(collection));
    if (cubeb_enumerate_devices(context, type, &collection) != CUBEB_OK) {
        return jayess_value_undefined();
    }
    devices = jayess_array_new();
    if (devices == NULL) {
        cubeb_device_collection_destroy(context, &collection);
        return jayess_value_undefined();
    }
    for (i = 0; i < collection.count; i++) {
        jayess_array_push_value(devices, jayess_audio_device_info_value(&collection.device[i]));
    }
    cubeb_device_collection_destroy(context, &collection);
    return jayess_value_from_array(devices);
}

static int jayess_audio_stream_ensure_capacity(jayess_audio_stream_state *state, size_t needed_samples) {
    float *expanded = NULL;
    size_t capacity = 0;
    if (state == NULL) {
        return 0;
    }
    if (needed_samples <= state->queued_sample_capacity) {
        return 1;
    }
    capacity = state->queued_sample_capacity > 0 ? state->queued_sample_capacity : 1024;
    while (capacity < needed_samples) {
        capacity *= 2;
    }
    expanded = (float *)realloc(state->queued_samples, capacity * sizeof(float));
    if (expanded == NULL) {
        return 0;
    }
    state->queued_samples = expanded;
    state->queued_sample_capacity = capacity;
    return 1;
}

static int jayess_audio_stream_push_event_locked(jayess_audio_stream_state *state, int event_code) {
    int *expanded = NULL;
    size_t capacity = 0;
    if (state == NULL) {
        return 0;
    }
    if (state->pending_event_count >= state->pending_event_capacity) {
        capacity = state->pending_event_capacity > 0 ? state->pending_event_capacity * 2 : 8;
        expanded = (int *)realloc(state->pending_events, capacity * sizeof(int));
        if (expanded == NULL) {
            return 0;
        }
        state->pending_events = expanded;
        state->pending_event_capacity = capacity;
    }
    state->pending_events[state->pending_event_count++] = event_code;
    return 1;
}

static void jayess_audio_stream_compact_locked(jayess_audio_stream_state *state) {
    size_t remaining = 0;
    if (state == NULL || state->read_sample_offset == 0) {
        return;
    }
    if (state->read_sample_offset >= state->queued_sample_count) {
        state->queued_sample_count = 0;
        state->read_sample_offset = 0;
        return;
    }
    remaining = state->queued_sample_count - state->read_sample_offset;
    memmove(state->queued_samples, state->queued_samples + state->read_sample_offset, remaining * sizeof(float));
    state->queued_sample_count = remaining;
    state->read_sample_offset = 0;
}

static long jayess_audio_stream_data_callback(cubeb_stream *stream, void *user_ptr, const void *input_buffer, void *output_buffer, long nframes) {
    jayess_audio_stream_state *state = (jayess_audio_stream_state *)user_ptr;
    long frame = 0;
    (void)stream;
    if (state == NULL || nframes <= 0) {
        return 0;
    }
    pthread_mutex_lock(&state->mutex);
    state->callback_count += 1;
    if (state->capture_mode) {
        size_t sample_count = (size_t)nframes * state->channels;
        if (input_buffer != NULL && jayess_audio_stream_ensure_capacity(state, state->queued_sample_count + sample_count)) {
            size_t i = 0;
            if (state->format == CUBEB_SAMPLE_FLOAT32NE) {
                const float *in = (const float *)input_buffer;
                for (i = 0; i < sample_count; i++) {
                    state->queued_samples[state->queued_sample_count + i] = in[i];
                }
            } else {
                const int16_t *in = (const int16_t *)input_buffer;
                for (i = 0; i < sample_count; i++) {
                    state->queued_samples[state->queued_sample_count + i] = (float)in[i] / 32768.0f;
                }
            }
            state->queued_sample_count += sample_count;
            state->captured_frames += (unsigned long long)nframes;
        }
        pthread_mutex_unlock(&state->mutex);
        return nframes;
    }
    if (output_buffer == NULL) {
        pthread_mutex_unlock(&state->mutex);
        return 0;
    }
    if (state->format == CUBEB_SAMPLE_FLOAT32NE) {
        float *out = (float *)output_buffer;
        for (frame = 0; frame < nframes; frame++) {
            uint32_t channel = 0;
            int have_frame = state->read_sample_offset + state->channels <= state->queued_sample_count;
            for (channel = 0; channel < state->channels; channel++) {
                if (have_frame) {
                    out[(frame * (long)state->channels) + (long)channel] = state->queued_samples[state->read_sample_offset + channel];
                } else {
                    out[(frame * (long)state->channels) + (long)channel] = 0.0f;
                }
            }
            if (have_frame) {
                state->read_sample_offset += state->channels;
                state->consumed_frames += 1;
            } else {
                state->underrun_count += 1;
                jayess_audio_stream_push_event_locked(state, 100);
            }
        }
    } else {
        int16_t *out = (int16_t *)output_buffer;
        for (frame = 0; frame < nframes; frame++) {
            uint32_t channel = 0;
            int have_frame = state->read_sample_offset + state->channels <= state->queued_sample_count;
            for (channel = 0; channel < state->channels; channel++) {
                if (have_frame) {
                    float sample = state->queued_samples[state->read_sample_offset + channel];
                    if (sample > 1.0f) {
                        sample = 1.0f;
                    } else if (sample < -1.0f) {
                        sample = -1.0f;
                    }
                    out[(frame * (long)state->channels) + (long)channel] = (int16_t)(sample * 32767.0f);
                } else {
                    out[(frame * (long)state->channels) + (long)channel] = 0;
                }
            }
            if (have_frame) {
                state->read_sample_offset += state->channels;
                state->consumed_frames += 1;
            } else {
                state->underrun_count += 1;
                jayess_audio_stream_push_event_locked(state, 100);
            }
        }
    }
    jayess_audio_stream_compact_locked(state);
    pthread_mutex_unlock(&state->mutex);
    return nframes;
}

static void jayess_audio_stream_state_callback(cubeb_stream *stream, void *user_ptr, cubeb_state stream_state) {
    jayess_audio_stream_state *state = (jayess_audio_stream_state *)user_ptr;
    (void)stream;
    if (state == NULL) {
        return;
    }
    pthread_mutex_lock(&state->mutex);
    state->last_state = (int)stream_state;
    state->running = stream_state == CUBEB_STATE_STARTED ? 1 : 0;
    jayess_audio_stream_push_event_locked(state, (int)stream_state);
    pthread_mutex_unlock(&state->mutex);
}

static void jayess_audio_stream_finalize(void *handle) {
    jayess_audio_stream_state *state = (jayess_audio_stream_state *)handle;
    if (state == NULL) {
        return;
    }
    if (state->stream != NULL) {
        cubeb_stream_stop(state->stream);
        cubeb_stream_destroy(state->stream);
        state->stream = NULL;
    }
    pthread_mutex_destroy(&state->mutex);
    free(state->queued_samples);
    free(state->pending_events);
    free(state);
}

static jayess_value *jayess_audio_stream_stats_value(jayess_audio_stream_state *state) {
    jayess_object *object = jayess_object_new();
    size_t queued_frames = 0;
    if (state == NULL || object == NULL) {
        return jayess_value_undefined();
    }
    pthread_mutex_lock(&state->mutex);
    if (state->channels > 0 && state->queued_sample_count >= state->read_sample_offset) {
        queued_frames = (state->queued_sample_count - state->read_sample_offset) / state->channels;
    }
    jayess_object_set_value(object, "sampleRate", jayess_value_from_number((double)state->sample_rate));
    jayess_object_set_value(object, "channels", jayess_value_from_number((double)state->channels));
    jayess_object_set_value(object, "latencyFrames", jayess_value_from_number((double)state->latency_frames));
    jayess_object_set_value(object, "format", jayess_value_from_string(jayess_audio_stream_format_text(state->format)));
    jayess_object_set_value(object, "running", jayess_value_from_bool(state->running));
    jayess_object_set_value(object, "queuedFrames", jayess_value_from_number((double)queued_frames));
    jayess_object_set_value(object, "submittedFrames", jayess_value_from_number((double)state->submitted_frames));
    jayess_object_set_value(object, "consumedFrames", jayess_value_from_number((double)state->consumed_frames));
    jayess_object_set_value(object, "capturedFrames", jayess_value_from_number((double)state->captured_frames));
    jayess_object_set_value(object, "callbacks", jayess_value_from_number((double)state->callback_count));
    jayess_object_set_value(object, "underruns", jayess_value_from_number((double)state->underrun_count));
    jayess_object_set_value(object, "lastState", jayess_value_from_string(jayess_audio_stream_state_text(state->last_state)));
    jayess_object_set_value(object, "capture", jayess_value_from_bool(state->capture_mode));
    pthread_mutex_unlock(&state->mutex);
    return jayess_value_from_object(object);
}

static jayess_value *jayess_audio_wav_value_from_decoded(float *decoded, uint32_t sample_rate, uint16_t channels, uint16_t source_format, size_t sample_count) {
    const char *source_format_text = source_format == 3 ? "wav-f32" : "wav-s16";
    jayess_array *values = NULL;
    jayess_value *typed = NULL;
    jayess_object *object = NULL;
    size_t i = 0;
    values = jayess_array_new();
    if (values == NULL) {
        return jayess_value_undefined();
    }
    for (i = 0; i < sample_count; i++) {
        jayess_array_push_value(values, jayess_value_from_number((double)decoded[i]));
    }
    typed = jayess_std_float32_array_new(jayess_value_from_array(values));
    object = jayess_object_new();
    if (object == NULL || typed == NULL) {
        return jayess_value_undefined();
    }
    jayess_object_set_value(object, "sampleRate", jayess_value_from_number((double)sample_rate));
    jayess_object_set_value(object, "channels", jayess_value_from_number((double)channels));
    jayess_object_set_value(object, "frames", jayess_value_from_number((double)(channels > 0 ? sample_count / channels : 0)));
    jayess_object_set_value(object, "format", jayess_value_from_string("f32"));
    jayess_object_set_value(object, "sourceFormat", jayess_value_from_string(source_format_text));
    jayess_object_set_value(object, "samples", typed);
    return jayess_value_from_object(object);
}

static jayess_value *jayess_audio_decoded_value_from_samples(float *decoded, uint32_t sample_rate, uint16_t channels, size_t frame_count, const char *source_format_text) {
    jayess_array *values = NULL;
    jayess_value *typed = NULL;
    jayess_object *object = NULL;
    size_t sample_count = frame_count * (size_t)channels;
    size_t i = 0;
    values = jayess_array_new();
    if (values == NULL) {
        return jayess_value_undefined();
    }
    for (i = 0; i < sample_count; i++) {
        jayess_array_push_value(values, jayess_value_from_number((double)decoded[i]));
    }
    typed = jayess_std_float32_array_new(jayess_value_from_array(values));
    object = jayess_object_new();
    if (object == NULL || typed == NULL) {
        return jayess_value_undefined();
    }
    jayess_object_set_value(object, "sampleRate", jayess_value_from_number((double)sample_rate));
    jayess_object_set_value(object, "channels", jayess_value_from_number((double)channels));
    jayess_object_set_value(object, "frames", jayess_value_from_number((double)frame_count));
    jayess_object_set_value(object, "format", jayess_value_from_string("f32"));
    jayess_object_set_value(object, "sourceFormat", jayess_value_from_string(source_format_text));
    jayess_object_set_value(object, "samples", typed);
    return jayess_value_from_object(object);
}

static jayess_value *jayess_audio_load_decoded_file(jayess_value *path_value, const char *function_name, const char *source_format_text, const char *error_text) {
    const char *path = jayess_expect_string(path_value, function_name);
    ma_decoder_config config = ma_decoder_config_init(ma_format_f32, 0, 0);
    ma_uint64 frame_count = 0;
    float *decoded = NULL;
    jayess_value *result = NULL;
    ma_result rv;
    ma_uint32 sample_rate = 0;
    ma_uint32 channels = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rv = ma_decode_file(path, &config, &frame_count, (void **)&decoded);
    if (rv != MA_SUCCESS || decoded == NULL) {
        jayess_throw_named_error("AudioError", error_text);
        return jayess_value_undefined();
    }
    sample_rate = config.sampleRate;
    channels = config.channels;
    if (sample_rate == 0 || channels == 0) {
        ma_free(decoded, NULL);
        jayess_throw_named_error("AudioError", error_text);
        return jayess_value_undefined();
    }
    result = jayess_audio_decoded_value_from_samples(decoded, sample_rate, (uint16_t)channels, (size_t)frame_count, source_format_text);
    ma_free(decoded, NULL);
    return result;
}

jayess_value *jayess_audio_create_context(jayess_value *name_value, jayess_value *backend_value) {
    const char *name = NULL;
    const char *backend = NULL;
    cubeb *context = NULL;
    int rv = 0;
    if (name_value != NULL && !jayess_value_is_nullish(name_value)) {
        name = jayess_expect_string(name_value, "jayess_audio_create_context");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
    }
    if (backend_value != NULL && !jayess_value_is_nullish(backend_value)) {
        backend = jayess_expect_string(backend_value, "jayess_audio_create_context");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
    }
    rv = cubeb_init(&context, name, backend);
    if (rv != CUBEB_OK || context == NULL) {
        return jayess_value_undefined();
    }
    return jayess_value_from_managed_native_handle("CubebContext", context, jayess_audio_context_finalize);
}

jayess_value *jayess_audio_destroy_context(jayess_value *context_value) {
    return jayess_value_from_bool(jayess_value_close_native_handle(context_value));
}

jayess_value *jayess_audio_backend_id(jayess_value *context_value) {
    cubeb *context = (cubeb *) jayess_expect_native_handle(context_value, "CubebContext", "jayess_audio_backend_id");
    const char *backend = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    backend = cubeb_get_backend_id(context);
    if (backend == NULL) {
        return jayess_value_undefined();
    }
    return jayess_value_from_string(backend);
}

jayess_value *jayess_audio_max_channel_count(jayess_value *context_value) {
    cubeb *context = (cubeb *) jayess_expect_native_handle(context_value, "CubebContext", "jayess_audio_max_channel_count");
    uint32_t max_channels = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (cubeb_get_max_channel_count(context, &max_channels) != CUBEB_OK) {
        return jayess_value_undefined();
    }
    return jayess_value_from_number((double)max_channels);
}

jayess_value *jayess_audio_list_output_devices(jayess_value *context_value) {
    cubeb *context = (cubeb *) jayess_expect_native_handle(context_value, "CubebContext", "jayess_audio_list_output_devices");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_audio_list_devices(context, CUBEB_DEVICE_TYPE_OUTPUT);
}

