jayess_value *jayess_audio_submit_playback_samples(jayess_value *stream_value, jayess_value *samples_value) {
    jayess_audio_stream_state *state = (jayess_audio_stream_state *)jayess_expect_native_handle(stream_value, "CubebPlaybackStream", "jayess_audio_submit_playback_samples");
    int sample_count = 0;
    int index = 0;
    unsigned char *raw_bytes = NULL;
    size_t raw_length = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (state->format == CUBEB_SAMPLE_S16NE) {
        raw_bytes = jayess_value_to_bytes_copy(samples_value, &raw_length);
        if (raw_bytes != NULL && raw_length > 0) {
            size_t offset = 0;
            if ((raw_length % 2) != 0) {
                jayess_bytes_free(raw_bytes);
                jayess_throw_named_error("AudioError", "s16 playback buffers must have an even byte length");
                return jayess_value_undefined();
            }
            sample_count = (int)(raw_length / 2);
            if (state->channels == 0 || sample_count % (int)state->channels != 0) {
                jayess_bytes_free(raw_bytes);
                jayess_throw_named_error("AudioError", "Playback sample count must align with channel count");
                return jayess_value_undefined();
            }
            pthread_mutex_lock(&state->mutex);
            if (!jayess_audio_stream_ensure_capacity(state, state->queued_sample_count + (size_t)sample_count)) {
                pthread_mutex_unlock(&state->mutex);
                jayess_bytes_free(raw_bytes);
                return jayess_value_undefined();
            }
            for (offset = 0; offset < raw_length; offset += 2) {
                int16_t sample_value;
#if defined(WORDS_BIGENDIAN) || defined(__BIG_ENDIAN__)
                sample_value = (int16_t)(((int)raw_bytes[offset] << 8) | (int)raw_bytes[offset + 1]);
#else
                sample_value = (int16_t)(((int)raw_bytes[offset + 1] << 8) | (int)raw_bytes[offset]);
#endif
                state->queued_samples[state->queued_sample_count + (offset / 2)] = (float)sample_value / 32768.0f;
            }
            state->queued_sample_count += (size_t)sample_count;
            state->submitted_frames += (unsigned long long)(sample_count / (int)state->channels);
            pthread_mutex_unlock(&state->mutex);
            jayess_bytes_free(raw_bytes);
            return jayess_value_from_number((double)(sample_count / (int)state->channels));
        }
    }
    sample_count = jayess_value_array_length(samples_value);
    if (sample_count <= 0) {
        return jayess_value_from_number(0);
    }
    if (state->channels == 0 || sample_count % (int)state->channels != 0) {
        jayess_throw_named_error("AudioError", "Playback sample count must align with channel count");
        return jayess_value_undefined();
    }
    pthread_mutex_lock(&state->mutex);
    if (!jayess_audio_stream_ensure_capacity(state, state->queued_sample_count + (size_t)sample_count)) {
        pthread_mutex_unlock(&state->mutex);
        return jayess_value_undefined();
    }
    for (index = 0; index < sample_count; index++) {
        state->queued_samples[state->queued_sample_count + (size_t)index] = (float)jayess_value_to_number(jayess_value_get_index(samples_value, index));
    }
    state->queued_sample_count += (size_t)sample_count;
    state->submitted_frames += (unsigned long long)(sample_count / (int)state->channels);
    pthread_mutex_unlock(&state->mutex);
    return jayess_value_from_number((double)(sample_count / (int)state->channels));
}

