jayess_value *jayess_audio_next_stream_event(jayess_value *stream_value) {
    jayess_audio_stream_state *state = NULL;
    int event_code = 0;
    jayess_object *object = NULL;
    state = (jayess_audio_stream_state *)jayess_value_as_native_handle(stream_value, "CubebPlaybackStream");
    if (state == NULL) {
        state = (jayess_audio_stream_state *)jayess_expect_native_handle(stream_value, "CubebCaptureStream", "jayess_audio_next_stream_event");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
    }
    pthread_mutex_lock(&state->mutex);
    if (state->pending_event_count == 0) {
        pthread_mutex_unlock(&state->mutex);
        return jayess_value_undefined();
    }
    event_code = state->pending_events[0];
    if (state->pending_event_count > 1) {
        memmove(state->pending_events, state->pending_events + 1, (state->pending_event_count - 1) * sizeof(int));
    }
    state->pending_event_count -= 1;
    pthread_mutex_unlock(&state->mutex);
    object = jayess_object_new();
    if (object == NULL) {
        return jayess_value_undefined();
    }
    jayess_object_set_value(object, "type", jayess_value_from_string(jayess_audio_event_text(event_code)));
    return jayess_value_from_object(object);
}

