jayess_value *jayess_audio_read_captured_samples(jayess_value *stream_value, jayess_value *frames_value) {
    jayess_audio_stream_state *state = (jayess_audio_stream_state *)jayess_expect_native_handle(stream_value, "CubebCaptureStream", "jayess_audio_read_captured_samples");
    int frames = 0;
    size_t available_frames = 0;
    size_t copy_frames = 0;
    size_t sample_count = 0;
    size_t i = 0;
    jayess_array *values = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    frames = (int)jayess_value_to_number(frames_value);
    if (frames <= 0) {
        return jayess_std_float32_array_new(jayess_value_from_array(jayess_array_new()));
    }
    values = jayess_array_new();
    if (values == NULL) {
        return jayess_value_undefined();
    }
    pthread_mutex_lock(&state->mutex);
    if (state->channels > 0 && state->queued_sample_count >= state->read_sample_offset) {
        available_frames = (state->queued_sample_count - state->read_sample_offset) / state->channels;
    }
    copy_frames = available_frames < (size_t)frames ? available_frames : (size_t)frames;
    sample_count = copy_frames * state->channels;
    for (i = 0; i < sample_count; i++) {
        jayess_array_push_value(values, jayess_value_from_number((double)state->queued_samples[state->read_sample_offset + i]));
    }
    state->read_sample_offset += sample_count;
    jayess_audio_stream_compact_locked(state);
    pthread_mutex_unlock(&state->mutex);
    return jayess_std_float32_array_new(jayess_value_from_array(values));
}

